// ============================================
// BUDGET PACER v2 - With distributed lock, per-teaser limits, time patterns
// ============================================

const lockData = $('Check Locks & Emergency').first().json;
const spendData = $('Fetch Today Spend').first().json;
const adsData = $('Fetch Active Ads').first().json;

// Safe access - DB nodes may return 0 rows
let geoItems = [];
try { geoItems = $('Fetch Geo Payouts').all().map(i => i.json); } catch(e) { geoItems = []; }
let crmItems = [];
try { crmItems = $('Fetch CRM Leads Today').all().map(i => i.json); } catch(e) { crmItems = []; }

const stats = spendData?.data?.result?.data || spendData?.data || (Array.isArray(spendData) ? spendData : []);
const ads = adsData?.data?.result?.data || adsData?.data || (Array.isArray(adsData) ? adsData : []);

// --- CONFIG ---
const DAILY_BUDGET = 200;  // $200/day (4x from original $50)

// --- GEO MAP ---
const geoMap = {};
geoItems.forEach(g => {
  if (g.country_code) geoMap[g.country_code] = {
    max_cpl: Number(g.max_cpl) || 75,
    min_bid: Number(g.min_bid) || 0.01,
    max_bid: Number(g.max_bid) || 0.15
  };
});

// --- CRM MAP ---
const crmMap = {};
crmItems.forEach(c => { crmMap[Number(c.ad_id)] = Number(c.total_leads) || 0; });

// --- Per-ad spend today ---
const adSpendMap = {};
let totalSpend = 0;
if (Array.isArray(stats)) {
  stats.forEach(s => {
    const spend = Number(s.money) || 0;
    totalSpend += spend;
    adSpendMap[s.ad_id] = spend;
  });
}

// --- TIME CALCULATIONS ---
const now = new Date();
const hour = now.getHours();
const hoursElapsed = hour + now.getMinutes() / 60;
const hoursRemaining = 24 - hoursElapsed;
const remainingBudget = DAILY_BUDGET - totalSpend;
const targetSpendPerHour = hoursRemaining > 0 ? remainingBudget / hoursRemaining : 0;
const actualSpendPerHour = hoursElapsed > 0 ? totalSpend / hoursElapsed : 0;

// --- TIME-OF-DAY ADJUSTMENT ---
// Evening (19:00+): auction is cheap, allow more spend
// Night (02:00-08:00): low traffic, expect less spend
let timeAdjustment = 1.0;
if (hour >= 19 || hour < 2) timeAdjustment = 1.3;  // Allow 30% more
if (hour >= 2 && hour < 8) timeAdjustment = 0.6;    // Expect 40% less

const adjustedTargetRate = targetSpendPerHour * timeAdjustment;

// --- ACCOUNT-LEVEL DECISION ---
let accountAction = 'HOLD';
let accountBidAdjustment = 1.0;
let accountReason = '';

// Overspending: spending 30% more than adjusted target
if (actualSpendPerHour > adjustedTargetRate * 1.3 && totalSpend > DAILY_BUDGET * 0.3) {
  accountAction = 'LOWER_ALL';
  accountBidAdjustment = 0.90;
  accountReason = `Overspending: $${actualSpendPerHour.toFixed(2)}/h vs adjusted target $${adjustedTargetRate.toFixed(2)}/h`;
}
// Underspending significantly
else if (actualSpendPerHour < adjustedTargetRate * 0.5 && remainingBudget > DAILY_BUDGET * 0.4 && hoursElapsed > 4) {
  accountAction = 'RAISE_ALL';
  accountBidAdjustment = 1.10;
  accountReason = `Underspending: $${actualSpendPerHour.toFixed(2)}/h vs adjusted target $${adjustedTargetRate.toFixed(2)}/h`;
}
// Budget nearly exhausted with hours remaining
else if (remainingBudget < DAILY_BUDGET * 0.05 && hoursRemaining > 4) {
  accountAction = 'LOWER_ALL';
  accountBidAdjustment = 0.75;
  accountReason = `Budget exhausted: $${remainingBudget.toFixed(2)} left for ${hoursRemaining.toFixed(1)}h`;
}

if (accountAction === 'HOLD') {
  return [{ json: {
    action: 'HOLD',
    reason: 'Budget pacing on track',
    total_spend: Math.round(totalSpend * 100) / 100,
    daily_budget: DAILY_BUDGET,
    actual_rate: Math.round(actualSpendPerHour * 100) / 100,
    target_rate: Math.round(adjustedTargetRate * 100) / 100,
    time_adjustment: timeAdjustment
  }}];
}

// --- PER-TEASER DECISIONS ---
const results = [];
if (Array.isArray(ads)) {
  ads.forEach(ad => {
    let currentBid = 0;
    const geos = [];
    if (ad.bids && Array.isArray(ad.bids)) {
      const extract = (node) => {
        if (node.bid) currentBid = currentBid || Number(node.bid);
        if (node.type === 'countries' && node.id) geos.push(node.id);
        const children = node.children ? (Array.isArray(node.children) ? node.children : Object.values(node.children)) : [];
        children.forEach(c => extract(c));
      };
      ad.bids.forEach(b => extract(b));
    }

    const primaryGeo = geos[0] || null;
    const geoPayout = primaryGeo && geoMap[primaryGeo] ? geoMap[primaryGeo] : { max_cpl: 75, min_bid: 0.01, max_bid: 0.15 };
    const adSpendToday = adSpendMap[ad.id] || 0;
    const adLeadsToday = crmMap[ad.id] || 0;

    // Per-teaser daily limit: maxCPL * 10 (generous, per user feedback)
    const perTeaserDailyLimit = geoPayout.max_cpl * 10;

    let bidAdj = accountBidAdjustment;
    let reason = accountReason;

    // Per-teaser overspend check
    if (adSpendToday >= perTeaserDailyLimit && adLeadsToday === 0) {
      // Spent a lot with 0 leads today -> pause this teaser
      results.push({
        json: {
          action: 'PAUSE_TEASER',
          reason: `Per-teaser limit: $${adSpendToday.toFixed(2)} >= $${perTeaserDailyLimit.toFixed(0)} (maxCPL*10) with 0 leads today`,
          ad_id: ad.id,
          geo: primaryGeo || 'unknown',
          current_bid: currentBid,
          new_bid: currentBid,
          ad_spend_today: Math.round(adSpendToday * 100) / 100,
          per_teaser_limit: Math.round(perTeaserDailyLimit),
          leads_today: adLeadsToday,
          total_spend: Math.round(totalSpend * 100) / 100,
          daily_budget: DAILY_BUDGET,
          bid_adjustment: 0,
          actual_rate: Math.round(actualSpendPerHour * 100) / 100,
          target_rate: Math.round(adjustedTargetRate * 100) / 100,
          ads_count: ads.length
        }
      });
      return;
    }

    // If teaser has leads and is profitable, don't touch it even during account overspend
    if (adLeadsToday > 0 && accountAction === 'LOWER_ALL') {
      // Profitable teasers are protected from blanket lower
      return;
    }

    let newBid = currentBid * bidAdj;
    if (newBid > geoPayout.max_bid) newBid = geoPayout.max_bid;
    if (newBid < geoPayout.min_bid) newBid = geoPayout.min_bid;
    newBid = Math.round(newBid * 10000) / 10000;

    if (Math.abs(newBid - currentBid) < 0.0001) return;

    results.push({
      json: {
        action: accountAction,
        reason: reason,
        ad_id: ad.id,
        geo: primaryGeo || 'unknown',
        current_bid: currentBid,
        new_bid: newBid,
        ad_spend_today: Math.round(adSpendToday * 100) / 100,
        per_teaser_limit: Math.round(perTeaserDailyLimit),
        leads_today: adLeadsToday,
        total_spend: Math.round(totalSpend * 100) / 100,
        daily_budget: DAILY_BUDGET,
        bid_adjustment: bidAdj,
        actual_rate: Math.round(actualSpendPerHour * 100) / 100,
        target_rate: Math.round(adjustedTargetRate * 100) / 100,
        ads_count: ads.length
      }
    });
  });
}

if (results.length === 0) {
  return [{ json: { action: 'HOLD', reason: 'No bid adjustments needed after per-teaser analysis' }}];
}

return results;

